    #[test]
    fn tcpmux_multipath_reassembles_one_ordered_file() {
        let nonce = format!(
            "{}-{}",
            std::process::id(),
            Instant::now().elapsed().as_nanos()
        );
        let input_path = PathBuf::from(format!("/tmp/zcutils-multipath-in-{nonce}"));
        let output_path = PathBuf::from(format!("/tmp/zcutils-multipath-out-{nonce}"));
        let data = (0..(256 * 1024))
            .map(|index| (index % 251) as u8)
            .collect::<Vec<_>>();
        let data_len = data.len() as u64;
        fs::write(&input_path, &data).unwrap();

        let listen_addresses = vec!["127.0.0.1".to_string(), "127.0.0.1".to_string()];
        let listeners =
            zc_tcpmux_bind_listeners_on_addresses(&listen_addresses, (0, 0), 4).unwrap();
        let ports = listeners
            .iter()
            .map(|listener| listener.local_addr().unwrap().port())
            .collect::<Vec<_>>();
        let receiver_output = output_path.clone();
        let receiver = thread::spawn(move || {
            zc_tcpmux_receive_parallel(
                listeners,
                0,
                &receiver_output,
                Some(data_len),
                ZcTcpmuxReceiveAssembly::Ordered,
                None,
                None,
                ZcTcpmuxEncryption::None,
                false,
                &ZcTcpmuxAffinityConfig::default(),
            )
        });

        let paths = vec![
            ZcTcpmuxDataPath {
                data_host: "127.0.0.1".to_string(),
                local_data_address: None,
                receive_listen_address: "127.0.0.1".to_string(),
            },
            ZcTcpmuxDataPath {
                data_host: "127.0.0.1".to_string(),
                local_data_address: None,
                receive_listen_address: "127.0.0.1".to_string(),
            },
        ];
        let input = fs::File::open(&input_path).unwrap();
        let sent = zc_tcpmux_copy_file_to_tcp_parallel(
            input,
            data_len,
            &paths,
            &ports,
            None,
            ZcTcpmuxEncryption::None,
            false,
            4096,
            &ZcTcpmuxAffinityConfig::default(),
        )
        .unwrap();
        let received = receiver.join().unwrap().unwrap();
        assert_eq!(sent, data_len);
        assert_eq!(received, data_len);
        assert_eq!(fs::read(&output_path).unwrap(), data);
        let _ = fs::remove_file(input_path);
        let _ = fs::remove_file(output_path);
    }

    #[test]
    fn tcpmux_multipath_writes_lane_contiguous_shards() {
        let nonce = format!(
            "{}-{}",
            std::process::id(),
            Instant::now().elapsed().as_nanos()
        );
        let input_path = PathBuf::from(format!("/tmp/zcutils-shards-in-{nonce}"));
        let output_path = PathBuf::from(format!("/tmp/zcutils-shards-out-{nonce}"));
        let chunk_bytes = 4096usize;
        let lanes = 4usize;
        let data = (0..(257 * 1024))
            .map(|index| (index % 251) as u8)
            .collect::<Vec<_>>();
        let data_len = data.len() as u64;
        fs::write(&input_path, &data).unwrap();

        let listen_addresses = vec!["127.0.0.1".to_string(), "127.0.0.1".to_string()];
        let listeners =
            zc_tcpmux_bind_listeners_on_addresses(&listen_addresses, (0, 0), lanes).unwrap();
        let ports = listeners
            .iter()
            .map(|listener| listener.local_addr().unwrap().port())
            .collect::<Vec<_>>();
        let receiver_output = output_path.clone();
        let receiver = thread::spawn(move || {
            zc_tcpmux_receive_parallel(
                listeners,
                0,
                &receiver_output,
                Some(data_len),
                ZcTcpmuxReceiveAssembly::Shards,
                None,
                None,
                ZcTcpmuxEncryption::None,
                false,
                &ZcTcpmuxAffinityConfig::default(),
            )
        });

        let paths = vec![
            ZcTcpmuxDataPath {
                data_host: "127.0.0.1".to_string(),
                local_data_address: None,
                receive_listen_address: "127.0.0.1".to_string(),
            },
            ZcTcpmuxDataPath {
                data_host: "127.0.0.1".to_string(),
                local_data_address: None,
                receive_listen_address: "127.0.0.1".to_string(),
            },
        ];
        let input = fs::File::open(&input_path).unwrap();
        let sent = zc_tcpmux_copy_file_to_tcp_parallel(
            input,
            data_len,
            &paths,
            &ports,
            None,
            ZcTcpmuxEncryption::None,
            false,
            chunk_bytes,
            &ZcTcpmuxAffinityConfig::default(),
        )
        .unwrap();
        let received = receiver.join().unwrap().unwrap();
        assert_eq!(sent, data_len);
        assert_eq!(received, data_len);
        assert!(zc_tcpmux_receive_shard_manifest_path(&output_path).exists());

        for lane in 0..lanes {
            let mut expected = Vec::new();
            let mut offset = lane * chunk_bytes;
            while offset < data.len() {
                let end = offset.saturating_add(chunk_bytes).min(data.len());
                expected.extend_from_slice(&data[offset..end]);
                offset = offset.saturating_add(chunk_bytes * lanes);
            }
            assert_eq!(
                fs::read(zc_tcpmux_receive_shard_path(&output_path, lane, None)).unwrap(),
                expected,
                "lane {lane} shard mismatch"
            );
        }
        let _ = fs::remove_file(input_path);
        let _ = fs::remove_file(zc_tcpmux_receive_shard_manifest_path(&output_path));
        for lane in 0..lanes {
            let _ = fs::remove_file(zc_tcpmux_receive_shard_path(&output_path, lane, None));
        }
    }

    #[test]
    fn tcpmux_ordered_stream_writer_reassembles_stdout_shape() {
        let (tx, rx) = mpsc::sync_channel::<ZcTcpmuxReceivedChunk>(4);
        tx.send(ZcTcpmuxReceivedChunk {
            offset: 4,
            data: b"efgh".to_vec(),
        })
        .unwrap();
        tx.send(ZcTcpmuxReceivedChunk {
            offset: 0,
            data: b"abcd".to_vec(),
        })
        .unwrap();
        tx.send(ZcTcpmuxReceivedChunk {
            offset: 8,
            data: b"ij".to_vec(),
        })
        .unwrap();
        drop(tx);

        let mut output = Vec::new();
        let (bytes, max_end) =
            zc_tcpmux_ordered_receive_stream_writer(&mut output, rx, Some(10)).unwrap();
        assert_eq!(bytes, 10);
        assert_eq!(max_end, 10);
        assert_eq!(output, b"abcdefghij");
    }

