#[derive(Clone, Copy, PartialEq, Eq)]
enum ZcRecvMode {
    Recv,
    Zcrx,
    Auto,
}

impl ZcRecvMode {
    fn parse(value: &str) -> io::Result<Self> {
        match value {
            "recv" | "normal" => Ok(Self::Recv),
            "zcrx" | "recv-zc" | "zero-copy-rx" => Ok(Self::Zcrx),
            "auto" | "auto-zcrx" | "zero-copy-auto" => Ok(Self::Auto),
            other => Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                format!("unknown receive mode {other:?}; use recv, zcrx, or auto"),
            )),
        }
    }

    fn label(self) -> &'static str {
        match self {
            Self::Recv => "recv",
            Self::Zcrx => "zcrx",
            Self::Auto => "auto",
        }
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum ZcZeroCopyPolicy {
    Required,
    Auto,
    Off,
}

impl ZcZeroCopyPolicy {
    fn parse(value: &str) -> io::Result<Self> {
        match value {
            "required" | "require" | "on" | "yes" | "true" | "1" | "zero-copy" | "zc" => {
                Ok(Self::Required)
            }
            "auto" | "try" | "fallback" => Ok(Self::Auto),
            "off" | "no" | "false" | "0" | "copy" | "copied" | "recv" | "send" => Ok(Self::Off),
            other => Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                format!("unknown zero-copy policy {other:?}; use required, auto, or off"),
            )),
        }
    }

    fn label(self) -> &'static str {
        match self {
            Self::Required => "required",
            Self::Auto => "auto",
            Self::Off => "off",
        }
    }

    fn apply_to_recv(self, recv: &mut ZcRecvOptions) {
        match self {
            Self::Required => {
                if recv.mode == ZcRecvMode::Recv {
                    recv.mode = ZcRecvMode::Auto;
                }
                recv.must_zero_copy = true;
            }
            Self::Auto => {
                recv.mode = ZcRecvMode::Auto;
                recv.must_zero_copy = false;
            }
            Self::Off => {
                recv.mode = ZcRecvMode::Recv;
                recv.must_zero_copy = false;
            }
        }
    }

    fn send_mode(self) -> UringSendMode {
        match self {
            Self::Required | Self::Auto => UringSendMode::SendZc,
            Self::Off => UringSendMode::Send,
        }
    }
}

struct ZcRecvOptions {
    mode: ZcRecvMode,
    ifname: Option<String>,
    rxq: u32,
    rxq_count: Option<usize>,
    must_zero_copy: bool,
}

impl ZcRecvOptions {
    fn zero_copy_policy(&self) -> ZcZeroCopyPolicy {
        if self.mode == ZcRecvMode::Recv {
            ZcZeroCopyPolicy::Off
        } else if self.must_zero_copy {
            ZcZeroCopyPolicy::Required
        } else {
            ZcZeroCopyPolicy::Auto
        }
    }
}

