fn apply_zc_common_env(
    source_port_base: Option<u16>,
    source_port_stride: Option<usize>,
    pin_cpus: Option<bool>,
    pin_base_cpu: Option<usize>,
    pin_cpu_count: Option<usize>,
    start_handshake: Option<bool>,
) {
    if let Some(value) = source_port_base {
        set_env_for_command("URING_PLAY_SOURCE_PORT_BASE", value.to_string());
    }
    if let Some(value) = source_port_stride {
        set_env_for_command("URING_PLAY_SOURCE_PORT_STRIDE", value.to_string());
    }
    if let Some(value) = pin_cpus {
        set_env_for_command("URING_PLAY_PIN_CPUS", if value { "1" } else { "0" });
    }
    if let Some(value) = pin_base_cpu {
        set_env_for_command("URING_PLAY_PIN_BASE_CPU", value.to_string());
    }
    if let Some(value) = pin_cpu_count {
        set_env_for_command("URING_PLAY_PIN_CPU_COUNT", value.to_string());
    }
    if let Some(value) = start_handshake {
        set_env_for_command("URING_PLAY_START_HANDSHAKE", if value { "1" } else { "0" });
    }
}

fn parse_zcmux_args<I>(args: I) -> io::Result<ZcMuxCli>
where
    I: Iterator<Item = String>,
{
    let mut opts = ZcMuxCli::default();
    let mut args = args.peekable();
    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--peer-addr" => opts.peer_addr = next_flag_value(&mut args, "--peer-addr")?,
            "--base-port" => {
                opts.base_port =
                    parse_u16_value(&next_flag_value(&mut args, "--base-port")?, "--base-port")?
            }
            "--lanes" => {
                opts.lanes = parse_usize_value(&next_flag_value(&mut args, "--lanes")?, "--lanes")?
            }
            "--connections-per-lane" => {
                opts.connections_per_lane = parse_usize_value(
                    &next_flag_value(&mut args, "--connections-per-lane")?,
                    "--connections-per-lane",
                )?
            }
            "--bytes-per-connection" => {
                opts.bytes_per_connection = parse_size_arg(
                    &next_flag_value(&mut args, "--bytes-per-connection")?,
                    "--bytes-per-connection",
                )?
            }
            "--chunk-bytes" => {
                opts.chunk_bytes = parse_size_arg(
                    &next_flag_value(&mut args, "--chunk-bytes")?,
                    "--chunk-bytes",
                )?
            }
            "--pipeline" => {
                opts.pipeline =
                    parse_usize_value(&next_flag_value(&mut args, "--pipeline")?, "--pipeline")?
            }
            "--workers" => {
                opts.workers =
                    parse_usize_value(&next_flag_value(&mut args, "--workers")?, "--workers")?
            }
            "--ring-entries" => {
                opts.ring_entries = parse_u32_value(
                    &next_flag_value(&mut args, "--ring-entries")?,
                    "--ring-entries",
                )?
            }
            "--send-mode" => {
                opts.send_mode = UringSendMode::parse(&next_flag_value(&mut args, "--send-mode")?)?;
                opts.zero_copy_policy = if opts.send_mode.uses_zc() {
                    ZcZeroCopyPolicy::Required
                } else {
                    ZcZeroCopyPolicy::Off
                };
            }
            "--zero-copy-send" | "--zero-copy" => {
                opts.zero_copy_policy =
                    ZcZeroCopyPolicy::parse(&next_flag_value(&mut args, "--zero-copy-send")?)?;
                opts.send_mode = opts.zero_copy_policy.send_mode();
            }
            "--source-port-base" => {
                opts.source_port_base = Some(parse_u16_value(
                    &next_flag_value(&mut args, "--source-port-base")?,
                    "--source-port-base",
                )?)
            }
            "--source-port-stride" => {
                opts.source_port_stride = Some(parse_usize_value(
                    &next_flag_value(&mut args, "--source-port-stride")?,
                    "--source-port-stride",
                )?)
            }
            "--pin-cpus" => {
                opts.pin_cpus = Some(parse_bool_arg(
                    &next_flag_value(&mut args, "--pin-cpus")?,
                    "--pin-cpus",
                )?)
            }
            "--pin-base-cpu" => {
                opts.pin_base_cpu = Some(parse_usize_value(
                    &next_flag_value(&mut args, "--pin-base-cpu")?,
                    "--pin-base-cpu",
                )?)
            }
            "--pin-cpu-count" => {
                opts.pin_cpu_count = Some(parse_usize_value(
                    &next_flag_value(&mut args, "--pin-cpu-count")?,
                    "--pin-cpu-count",
                )?)
            }
            "--start-handshake" => {
                opts.start_handshake = Some(parse_bool_arg(
                    &next_flag_value(&mut args, "--start-handshake")?,
                    "--start-handshake",
                )?)
            }
            other => {
                return Err(io::Error::new(
                    io::ErrorKind::InvalidInput,
                    format!("unknown zcmux option {other:?}"),
                ));
            }
        }
    }
    Ok(opts)
}

#[allow(clippy::too_many_arguments)]
fn tcp_bench_uring_mux_send_with_policy(
    addr: &str,
    base_port: u16,
    ports: usize,
    connections_per_port: usize,
    bytes_per_connection: usize,
    chunk_bytes: usize,
    pipeline: usize,
    workers: usize,
    ring_entries: u32,
    send_mode: UringSendMode,
    zero_copy_policy: ZcZeroCopyPolicy,
) -> io::Result<()> {
    if zero_copy_policy == ZcZeroCopyPolicy::Auto && send_mode.uses_zc() {
        match kernel_supports_request_opcode(IORING_OP_SEND_ZC) {
            Ok(true) => {}
            Ok(false) => {
                eprintln!("zcmux-send-zc-auto: send-zc opcode unavailable; falling back to send");
                return tcp_bench_uring_mux_send(
                    addr,
                    base_port,
                    ports,
                    connections_per_port,
                    bytes_per_connection,
                    chunk_bytes,
                    pipeline,
                    workers,
                    ring_entries,
                    UringSendMode::Send,
                );
            }
            Err(err) => {
                eprintln!(
                    "zcmux-send-zc-auto: io_uring opcode query failed ({err}); falling back to send"
                );
                return tcp_bench_uring_mux_send(
                    addr,
                    base_port,
                    ports,
                    connections_per_port,
                    bytes_per_connection,
                    chunk_bytes,
                    pipeline,
                    workers,
                    ring_entries,
                    UringSendMode::Send,
                );
            }
        }
        if let Err(err) = validate_uring_send_mode_location(send_mode) {
            eprintln!("zcmux-send-zc-auto: send-zc unavailable ({err}); falling back to send");
            return tcp_bench_uring_mux_send(
                addr,
                base_port,
                ports,
                connections_per_port,
                bytes_per_connection,
                chunk_bytes,
                pipeline,
                workers,
                ring_entries,
                UringSendMode::Send,
            );
        }
    }
    tcp_bench_uring_mux_send(
        addr,
        base_port,
        ports,
        connections_per_port,
        bytes_per_connection,
        chunk_bytes,
        pipeline,
        workers,
        ring_entries,
        send_mode,
    )
}

fn zcmux(args: impl Iterator<Item = String>) -> io::Result<()> {
    let opts = parse_zcmux_args(args)?;
    apply_zc_common_env(
        opts.source_port_base,
        opts.source_port_stride,
        opts.pin_cpus,
        opts.pin_base_cpu,
        opts.pin_cpu_count,
        opts.start_handshake,
    );
    println!(
        "zcmux: peer_addr={} base_port={} lanes={} connections_per_lane={} \
         bytes_per_connection={} chunk_bytes={} pipeline={} workers={} ring_entries={} send_mode={} zero_copy={}",
        opts.peer_addr,
        opts.base_port,
        opts.lanes,
        opts.connections_per_lane,
        opts.bytes_per_connection,
        opts.chunk_bytes,
        opts.pipeline,
        opts.workers,
        opts.ring_entries,
        opts.send_mode.name(),
        opts.zero_copy_policy.label()
    );
    tcp_bench_uring_mux_send_with_policy(
        &opts.peer_addr,
        opts.base_port,
        opts.lanes,
        opts.connections_per_lane,
        opts.bytes_per_connection,
        opts.chunk_bytes,
        opts.pipeline,
        opts.workers,
        opts.ring_entries,
        opts.send_mode,
        opts.zero_copy_policy,
    )
}

